export const meta = {
  name: 'qa-nablarch-batch-startup',
  description: 'QA workflow: Nablarchバッチ起動と-requestPathの書き方',
  phases: [
    { title: 'SemanticSearch', detail: 'Search knowledge pages' },
    { title: 'ReadSections', detail: 'Read selected sections' },
    { title: 'GenerateAnswer', detail: 'Generate and verify answer' },
  ],
}

phase('SemanticSearch')

const query = "Nablarchバッチアプリケーションはどのように起動しますか？-requestPathの書き方を教えてください（処理方式: Nablarchバッチ）（目的: 実装したい）"

const SEARCH_SCHEMA = {
  type: "object",
  properties: {
    selected_pages: {
      type: "array",
      items: {
        type: "object",
        properties: {
          path: { type: "string" },
          reason: { type: "string" }
        },
        required: ["path", "reason"]
      }
    },
    excluded_pages: {
      type: "array",
      items: {
        type: "object",
        properties: {
          path: { type: "string" },
          reason: { type: "string" }
        },
        required: ["path", "reason"]
      }
    },
    selected_sections: {
      type: "array",
      items: {
        type: "object",
        properties: {
          file: { type: "string" },
          section_id: { type: "string" },
          relevance: { type: "string", enum: ["high", "partial"] },
          reason: { type: "string" }
        },
        required: ["file", "section_id", "relevance", "reason"]
      }
    },
    excluded_sections: {
      type: "array",
      items: {
        type: "object",
        properties: {
          file: { type: "string" },
          section_id: { type: "string" },
          reason: { type: "string" }
        },
        required: ["file", "section_id", "reason"]
      }
    }
  },
  required: ["selected_pages", "excluded_pages", "selected_sections", "excluded_sections"]
}

const searchResult = await agent(
  `You are executing semantic-search for a QA workflow in the nabledge-6 knowledge base.

Query: "${query}"

Processing type: Nablarchバッチ
Purpose: 実装したい

## Your Task

1. List the available knowledge pages by running:
   \`\`\`bash
   ls /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/knowledge/
   \`\`\`

2. Select the most relevant pages for this query. Focus on pages related to:
   - Nablarchバッチの起動方法
   - -requestPath パラメータ
   - バッチアプリケーションの実装

3. For each selected page, read its table of contents or summary to identify specific sections.
   Use: \`bash scripts/read-sections.sh "<file>:s1"\` to read section 1 (usually overview/TOC)
   Working directory: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/

4. Select up to 15 most relevant sections total, marking each as "high" or "partial" relevance.
   - high: directly answers the question
   - partial: provides supporting context

5. For EACH page you examine, record whether it was selected or excluded and why.
   For EACH section you evaluate, record whether it was selected or excluded and why.

Return structured results with all pages examined (selected and excluded) and all sections evaluated.`,
  { label: 'semantic-search', phase: 'SemanticSearch', schema: SEARCH_SCHEMA }
)

log(`Found ${searchResult.selected_sections.length} selected sections from ${searchResult.selected_pages.length} pages`)

phase('ReadSections')

// Select sections: all high first, then partial, max 10
const highSections = searchResult.selected_sections.filter(s => s.relevance === 'high')
const partialSections = searchResult.selected_sections.filter(s => s.relevance === 'partial')
const sectionsToRead = [...highSections, ...partialSections].slice(0, 10)

const READ_SCHEMA = {
  type: "object",
  properties: {
    sections_content: { type: "string" },
    read_sections: {
      type: "array",
      items: { type: "string" }
    }
  },
  required: ["sections_content", "read_sections"]
}

const sectionArgs = sectionsToRead.map(s => `"${s.file}:${s.section_id}"`)

const readResult = await agent(
  `Read the following knowledge sections and return their content.

Run this command from /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/:
\`\`\`bash
bash scripts/read-sections.sh ${sectionArgs.join(' ')}
\`\`\`

Return the full output as sections_content, and list all section references as read_sections.
Section references format: "filename.json:sN"

Sections to read:
${sectionsToRead.map(s => `- ${s.file}:${s.section_id}`).join('\n')}`,
  { label: 'read-sections', phase: 'ReadSections', schema: READ_SCHEMA }
)

log(`Read ${readResult.read_sections.length} sections`)

phase('GenerateAnswer')

const ANSWER_SCHEMA = {
  type: "object",
  properties: {
    answer_text: { type: "string" },
    verify_result: { type: "string", enum: ["PASS", "FAIL"] },
    issues: {
      type: "array",
      items: { type: "string" }
    },
    final_answer: { type: "string" },
    answer_sections_used: {
      type: "array",
      items: {
        type: "object",
        properties: {
          ref: { type: "string" },
          reason: { type: "string" }
        },
        required: ["ref", "reason"]
      }
    },
    answer_sections_unused: {
      type: "array",
      items: {
        type: "object",
        properties: {
          ref: { type: "string" },
          reason: { type: "string" }
        },
        required: ["ref", "reason"]
      }
    }
  },
  required: ["answer_text", "verify_result", "final_answer", "answer_sections_used", "answer_sections_unused"]
}

const answerResult = await agent(
  `You are generating a Japanese answer for the following question about Nablarch batch application startup.

## Question
Nablarchバッチアプリケーションはどのように起動しますか？-requestPathの書き方を教えてください

## Knowledge Sections Content
${readResult.sections_content}

## Task

### Step 5: Generate Answer

Generate a Japanese answer following this format (max 500 tokens, up to 800 for complex questions):

**結論**: Direct answer to the question (1-2 sentences with specific method names, class names, approaches)

**根拠**: Code examples, configuration examples, or spec information
- Show code/config examples in code blocks
- Priority: implementation example > configuration > API spec > conceptual explanation
- Quote code examples from sections verbatim (do not modify)

**注意点**: Constraints, resource management, common mistakes (omit if nothing applies)

参照: Only sections actually cited (file.json:sN format, omit category path)

### Step 6: Verify Answer

Check each Nablarch-specific claim in the answer against the knowledge sections.

Claim categories to check:
- API names (method names, annotation names)
- Class names
- Configuration methods
- Behavior specs
- Constraints
- Parameters (like -requestPath format)

Do NOT check: general Java knowledge, general programming concepts, flow descriptions, general web concepts.

For each claim: determine if it's directly stated in sections (PASS) or not explicitly stated (FAIL).

### Step 7: Handle Result

If PASS: final_answer = answer_text
If FAIL: regenerate answer without the failing claims, save as final_answer

Return:
- answer_text: the initial generated answer
- verify_result: PASS or FAIL
- issues: list of any unsupported claims (empty if PASS)
- final_answer: the verified final answer
- answer_sections_used: sections actually cited with reason
- answer_sections_unused: sections read but not used with reason`,
  { label: 'generate-answer', phase: 'GenerateAnswer', schema: ANSWER_SCHEMA }
)

return {
  searchResult,
  readResult,
  answerResult,
  sectionsToRead
}

